window.__QUIZ_DATA__=[{"id":"objective>Geography>2010>1","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The feature marked X-Y is a/an","images":["data:image/png;base64,"],"options":{"A":"dry valley","B":"crater lake","C":"plateau","D":"alluvial fan"},"answer":"A","explanation":"The featured marked x-y is a dry valley. This is because the section XY contains low lands that exist between hills.   N.B: It should be noted that a valley can be defined as a low land that exist between two hills.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>2","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"River Owen is a/an","images":[],"options":{"A":"distributory of River Oshe","B":"tributary of River Oshe","C":"delta","D":"estuary"},"answer":"B","explanation":"River Owerri is a tributary of River Oshe   N.B: A tributary is a natural water stream that flows into a larger river or other body of water.      A \u21d2 Confluence   X \u21d2 Tributary   Y \u21d2 Tributary   Z \u21d2 large River","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>3","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Sugar cane can easily be grown in the","images":[],"options":{"A":"eastern part of the map","B":"south eastern part of the map","C":"northern part of the map","D":"south western part of the map"},"answer":"D","explanation":"Sugar cane can easily be grown in the south-western of the map. This is because the south-western part of the map contains the necessary materials (climatic and environmental) needed for the cultivation of sugar cane. We have grasslands river and areas liable to flooding in the south-Western part of the major map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>4","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : COMMUNICATION","question":"OFOT is a","images":[],"options":{"A":"nodal town","B":"port town","C":"defence town","D":"fishing town"},"answer":"A","explanation":"OFOT is a nodal town as it is an area organized around a node, or focal point, defined by interactions of connections.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>5","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The long stretch of highland in the northern part of the map is","images":[],"options":{"A":"caldera","B":"geyser","C":"ridge","D":"plateau"},"answer":"C","explanation":"The long stretch of highland in the northern part of the map is a ridge   N.B: A ridge or mountain ridge are geological features consisting of a chain of mountains or hils that form a continuous elevated crest for some distance.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>6","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The bearing of Agaba from Deog is about","images":[],"options":{"A":"110o","B":"140o","C":"160o","D":"190o"},"answer":"B","explanation":"The bearing of Agaba from Deog is 140o","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>7","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The road network on the map","images":[],"options":{"A":"avoids lowlands","B":"avoids highlands","C":"moves through valleys","D":"move along the plateau"},"answer":"B","explanation":"The road network on the map extends away from, i.e. avoid high lands","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>8","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of these statements is true about the relief of the map?","images":[],"options":{"A":"The central area is higher than other areas","B":"The northern area is generally low in elevation","C":"The central area is lower than other areas","D":"The southern areas is generally low elevation"},"answer":"C","explanation":"The relief of the map is such that the central area is lower than the area","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>9","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following is not a likely occupation of the people in Agaba?","images":[],"options":{"A":"Farming","B":"Mining","C":"Trading","D":"Cattle rearing"},"answer":"B","explanation":"We have many regions with scattered cultivation, hence farming is a likely occupation. We have reliable road networks and settlements that are connected, hence trading is a likely occupation. Also, there are grasslands, hence cattle rearing is a likely occupation   There is only one region (OFOT) in the map where mining is done, hence mining cannot be a likely occupation of the people in Agaba","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>10","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : SETTLEMENT","question":"OFOT can be described as a","images":[],"options":{"A":"fishing town","B":"recreational centre","C":"mining settlement","D":"ship building centre"},"answer":"C","explanation":"OFOT is the only place where mining takes place, hence we may describe OFOT as a mining settlement","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>11","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The annual temperature range for the station is","images":[],"options":{"A":"5.5oC","B":"11oC","C":"26oC","D":"27oC"},"answer":"B","explanation":"The annual temperature range for the station is   \u21d2 Highest temperature value - Lowest temperature value   Maximum Temperature value - Minimum Temperature   = 33oC - 22oC = 11oC","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>12","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The climatic data above can be represented by","images":[],"options":{"A":"divided circles","B":"chloropleth maps","C":"flow line maps","D":"bar and line graphs"},"answer":"D","explanation":"Bar line and graphic is the most suitable analytical tool to represent the climatic data","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>13","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The climatic data above most probably represents","images":[],"options":{"A":"Hot desert climate","B":"Mediterranean climate","C":"Tropical continental climate","D":"Warm temperature"},"answer":"C","explanation":"The climatic data presented in the question most probably represents a tropical continental climates","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>14","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"A true bearing is the angle which a line makes from the observer's position to an object with the same line pointing to","images":[],"options":{"A":"Magnetic North","B":"Magnetic Variation","C":"True North","D":"Southern Hemisphere"},"answer":"C","explanation":"A true bearing is the angle which a line makes from the observer's position to an object with the line pointing to the true North","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>15","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"It is noon at Point X (longitude 0o), while it is 10.00 pm at Point Y. What is the longitude of point Y?","images":[],"options":{"A":"150oE","B":"140oW","C":"130oE","D":"120oW"},"answer":"A","explanation":"It should be noted that: 1o = 4 minutes (15o = 1 hour)   \u21d2  x = 10 hours (noon to 10:00pm)    x = 150o \u21d2 The place is at longitude 150oE","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>16","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The part of the lithosphere which forms the ocean floor is","images":[],"options":{"A":"sial","B":"sima","C":"nikel","D":"nife"},"answer":"B","explanation":"\u21d2 Sima: Is an assembly of rocks, rich in silica and magnesium that constitutes the layer of the earth's crust and is found beneath the ocean floors and the sial of continents","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>17","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following lines could be described as a great circle?","images":[],"options":{"A":"Tropic of Cancer","B":"Tropic of Caprocorn","C":"Equator","D":"Arctic Circle"},"answer":"C","explanation":"A great circle is a circle on the surface of a sphere that has the same diameter as the sphere. It represents the shortest distance between any two points on the surface of the sphere. The equator is a great circle because it divides the Earth into two equal halves and represents the largest possible circle that can be drawn on the Earth's surface.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>18","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The northern and southern limits of the apparent movement of the sun is marked by the","images":[],"options":{"A":"Tropic of Capricorn and Equator","B":"Tropics of Cancer and Capricorn","C":"Horse Latitudes","D":"North pole and South pole"},"answer":"B","explanation":"The northern and southern limits of the apparent movement of the sun is marked by the Tropics of Cancer and Capricorn.      \u21d2 The Tropic of Cancer is the most northern latitude on the Earth where the sun appears directly overhead. The Tropic of sun can appear directly appears overhead.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>19","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is a true characteristic of sedimentary rocks? They","images":[],"options":{"A":"are laid down in strata","B":"are crystalline","C":"have high resistance of erosion","D":"are basaltic in nature"},"answer":"A","explanation":"Sedimentary rocks are formed from the accumulation of sediments, such as sand or minerals, that are laid down in layers or strata. This process is known as sedimentation. The other options are incorrect because sedimentary rocks are not typically crystalline, they do not have high resistance to erosion, and they are not basaltic in nature.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>20","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following fold mountains is found in Africa?","images":[],"options":{"A":"Himalayas","B":"Alps","C":"Atlas","D":"Rockies"},"answer":"C","explanation":"The Atlas Mountains are a mountain range in North Africa that stretches through Morocco, Algeria, and Tunisia. The Himalayas, Alps, and Rockies are all located outside of Africa.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>21","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Resurgent springs usually occurs in","images":[],"options":{"A":"rift valleys","B":"u-shaped valleys","C":"limestone areas","D":"glaciated areas"},"answer":"C","explanation":"Resurgent springs usually occur in limestone areas. This is because limestone is a permeable rock that allows water to seep through it and accumulate in underground reservoirs. When the pressure becomes too great, the water is forced to the surface, creating a resurgent spring. Rift valleys, u-shaped valleys, and glaciated areas do not typically have the geological conditions necessary for the formation of resurgent springs.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>22","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following landforms is not produced by faulting?","images":[],"options":{"A":"Fault Scarp","B":"Rift Valley","C":"Sill","D":"Horst"},"answer":"C","explanation":"Major landforms caused by faulting include:      \u21d2 Horst","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>23","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The process of removing soluble substance such as mineral salt into lower layers of the soil is called","images":[],"options":{"A":"translocation","B":"leaching","C":"eluviation","D":"illuviation"},"answer":"B","explanation":"The process of removing soluble substance such as mineral salt into layers of the soil is called \"Leaching.\"","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>24","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a process of chemical weathering?","images":[],"options":{"A":"Oxidation","B":"Attrition","C":"Hydration","D":"Carbonation"},"answer":"B","explanation":"The processes involved in chemical weathering include:  \u21d2 Hydrolysis (Hydration)  \u21d2 Oxidation   \u21d2 Carbonation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>25","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Sea tides caused mainly by the influence of","images":[],"options":{"A":"earth's rotation","B":"asteroids","C":"the stars","D":"the sun"},"answer":"A","explanation":"Sea tides are caused mainly by the influence of the rotation of the earth about its axis.   N.B: Tides are the rise and fall of the sea levels caused by the combined effects of the gravitational forces exerted by the Moon and Sun and the rotation of the Earth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>26","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The most important active factor of soil formation is","images":[],"options":{"A":"time","B":"releif","C":"slope","D":"climate"},"answer":"D","explanation":"The most important active factor of soil formation is climate. Climate influences the rate of weathering and humus accumulation, which are key processes in soil formation. Weathering is the breaking down of rocks, soil, and minerals as well as wood and artificial materials through contact with the Earth's atmosphere, water, and biological organisms. Humus is the organic component of soil, formed by the decomposition of leaves and other plant material by soil microorganisms.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>27","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following has the highest level of salinity?","images":[],"options":{"A":"Baltic sea","B":"Antartic ocean","C":"Mediteranean sea","D":"Atlantic ocean"},"answer":"A","explanation":"Atlantic ocean has the highest salinity (salt concentration) in the list of options","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>28","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following is not a form of precipitation?","images":[],"options":{"A":"Hail","B":"Dust","C":"Dew","D":"Snow"},"answer":"B","explanation":"\"Dust\" is not a form of precipitation.  N.B: Precipitation is rain, snow, dew, sleet or hail - any kind of weather condition where something is falling from the sky. precipitation has to do with things falling down, and from the sky alone. It is also what happens in chemical reactions when a solid settles to the bottom of a solution","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>29","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"It has humidity of over 90%, with rainfall in all months. \"The statement describes the","images":[],"options":{"A":"Equatorial climate","B":"Desert climate","C":"Warm temperature climate","D":"Mediterranean climate"},"answer":"A","explanation":"\"It has humidity of over 90% with rainfall in all months\"   \u21d2This expression describes the equatorial climate   N.B: Equitorial regions generally have the following characteristics   (1) Heavy rainfall   (2) Humidity (avg. humidity is 90%)  (3) temperature between 28oc and 38oc   (4) Diverse range of plants due to excessive rainfall and temperature   (5) Dense forest   (6) In equatorial regions, it is basically summer all year round","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>30","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The forest is both dense and luxuriant and contains a great variety of plants with broad leaved trees\" This statement describes the","images":[],"options":{"A":"Savannah","B":"Tropical rain forest","C":"Mediterranean woodland","D":"Warm temperate forest"},"answer":"B","explanation":"\"The forest is both dense and luxuriant and contains a great variety of plants with broad leaved trees\"   \u21d2This expression describes the tropical rain forest","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>31","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following is not a major benefit of Savanna vegetation?","images":[],"options":{"A":"Livestock farming","B":"Arable crop cultivation","C":"Aqua culture","D":"Game reserves"},"answer":"C","explanation":"\"Aqua culture i.e is the farming of fish, crustaceans, molluscs, aquatic plants, algae, and other organism, is not a major benefit of savanna vegetation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>32","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"The study of the continuous interaction between living things and their environment is known as","images":[],"options":{"A":"Ecology","B":"Energy cycle","C":"Biology","D":"Geology"},"answer":"A","explanation":"Ecology is the branch of biology that studies the interactions among organisms and their biophysical environment, which includes both biotic and abiotic components. It involves studying the relationships between living organisms and their physical surroundings. So, the continuous interaction between living things and their environment is known as Ecology.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>33","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following has very dense population?","images":[],"options":{"A":"The equatorial lowland of South America","B":"The northern region of Canada","C":"The north eastern seaboard of U.S.A","D":"The western region of Australia"},"answer":"C","explanation":"The northeastern seaboard of the U.S.A is known for its high population density. This region includes major cities like New York, Boston, Philadelphia, and Washington D.C. The other options like the equatorial lowland of South America, the northern region of Canada, and the western region of Australia are known for their low population densities.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>34","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following represents an increasing order in the size of settlement?","images":[],"options":{"A":"Isolated farmstead \u2192 hamlet \u2192 village \u2192 town","B":"Town \u2192 village \u2192 hamlet \u2192 isolated farmstead","C":"Isolated farmstead \u2192 village \u2192 hamlet \u2192 town","D":"Hamlet \u2192 village \u2192 town \u2192 isolated farmstead"},"answer":"A","explanation":"Isolated farmstead \u2192 Hamlet \u2192 village \u2192 Towns     The arrangement above shows the settlement in order of increasing complexity","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>35","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"\"It is an area of great industrial and agricultural activities and hence supports great concentration of people\" This statement best describes","images":[],"options":{"A":"the Amazon basia","B":"the Northern East U.S.A","C":"the Niger valley","D":"North Africa"},"answer":"B","explanation":"\"It is an area of great industrial and agricultural activities and hence support great concentration of people\"   \u21d2 This statement simply describes the North east of U.S.A","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>36","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"\"It is the lowest and cheapest means of transporting bulky goods over long distance among nations\". This statement best describes","images":[],"options":{"A":"road transport","B":"rail transport","C":"air transport","D":"sea transport"},"answer":"D","explanation":"\"It is the slowest and cheapest means of transport and is used for transporting bulky goods over long distances among nations\"   * This statement describes sea transport   N.B: Sea transport is the cheapest and the oldest mode of transport. The cost of water transport is also very less. It has the greatest carrying capacity and is most suitable for carrying bulky goods over long distance","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>37","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The role of transport in economic development of any nation include all except","images":[],"options":{"A":"national disintegration","B":"movement of goods and services","C":"opening up new lands and areas","D":"provision of employment"},"answer":"A","explanation":"Transportation is aimed at promoting economic development in the following ways:  * Opening up now lands and areas  * Provision of employment   * Movement of goods and services (enhances supply chain efficiency)  * Increases productivity","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>38","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"All the following are benefits of irrigation farming except","images":[],"options":{"A":"provision of employment","B":"making early planting possible","C":"making farmers depends solely on rainfall","D":"bumper harvest"},"answer":"C","explanation":"Irrigation farming is a farming method that allows farmers to supply a specific amount of water to their crops at specific intervals. This method of farming reduces the farmer's dependence on rainfall as it provides a more controlled water supply for the crops. Therefore, the statement 'making farmers depends solely on rainfall' is not a benefit of irrigation farming.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>39","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"It is possible to harness solar energy in all the following countries except","images":[],"options":{"A":"Angola","B":"Australia","C":"Greenland","D":"Thailand"},"answer":"C","explanation":"Solar energy can be harnessed in any part of the world that receives sunlight. However, the efficiency of harnessing solar energy depends on the intensity and duration of sunlight. Greenland, being located in the high latitudes, experiences long periods of darkness especially during the winter months. Therefore, it is less feasible to harness solar energy in Greenland compared to the other countries listed.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>40","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The most important trading partner of Anglophone West Africa countries is","images":[],"options":{"A":"Canada","B":"Korea","C":"France","D":"United Kingdom"},"answer":"D","explanation":"Anglophone West Africa countries refer to the English-speaking countries in West Africa. These countries were colonized by Britain and have maintained strong economic ties with the United Kingdom. Therefore, the United Kingdom is the most important trading partner of Anglophone West Africa countries.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>41","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The smallest ocean in the world is the","images":[],"options":{"A":"Indian ocean","B":"Pacific ocean","C":"Artic ocean","D":"Atlantic ocean"},"answer":"C","explanation":"The Arctic Ocean is the smallest of the world's five ocean basins. A polar bear walks on the frozen surface of the Arctic Ocean. The freezing environment provides a home for a diverse range of creatures. With an area of about 14.05 million sq km, the Arctic Ocean is about 1.5 times as big as the United States.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2010>42","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"One of the major problems of manufacturing industries in Tropical Africa is","images":[],"options":{"A":"high demand for manufactured products","B":"inadequate raw materials","C":"high quantity of industrial labour","D":"high cost of labour"},"answer":"B","explanation":"\"Inadequate raw materials\" is one of the major problems facing manufacturing industries in Tropical Africa","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>43","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Man made distribution of water to farmlands in areas which suffer from inadequate rainfall is called","images":[],"options":{"A":"water resource management","B":"irrigation","C":"mulching","D":"erable farming"},"answer":"B","explanation":"Irrigation is man made distribution of water to farmlands, in areas which suffer from inadequate rainfall","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>44","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"In which of the following vegetation belts is lumbering an important economic activity?","images":[],"options":{"A":"Sahel savanna","B":"Tundra","C":"Sudan savanna","D":"Tropical rainforest"},"answer":"D","explanation":"Lumbering is a very important activity in Liberia   N.B: The presence of dense tropical forest provides ready sources of valuable timber.   - Lumbering is defined as the business of trade of cutting, transporting, preparing or selling of economic trees of the forest.  - Liberi is a tropical country in West Africa","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>45","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Lumbering is a very important activity in","images":[],"options":{"A":"Libya","B":"Namibia","C":"Liberia","D":"Algeria"},"answer":"C","explanation":"Lumbering is a very important activity in Liberia. Liberia is located in West Africa and is covered by high percentage of forest. It is rich in timber resources, making lumbering a significant economic activity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>46","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"All the following countries lie on the Equator except","images":[],"options":{"A":"kenya","B":"Ghana","C":"Somalia","D":"Gabon"},"answer":"B","explanation":"There are 13 countries that lie along the equator   * Ecuador   * Colombia   * Brazil   * Gabon  * Congo   * Uganda  * Kenya   * Sac Tome   * Somalia   * Maldives   * Indonesia   * Kiribati   * Congo DR","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>47","subject":"Geography","year":"2010","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Nature mostly intervenes in the state of balance in land ecosystem through","images":[],"options":{"A":"Earth's revolution","B":"Climatic change","C":"earth equilibrium","D":"Earth rotation"},"answer":"B","explanation":"Nature intervenes in the state of balance in land ecosystems primarily through climatic changes. Climatic changes can alter the conditions of an ecosystem, affecting the types of organisms that can survive there. Changes in temperature, precipitation, and seasonal patterns can all disrupt the balance of an ecosystem. Earth's revolution and rotation are more related to the changes in seasons and day-night cycle respectively, while earth equilibrium is not a direct factor affecting ecosystems.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>48","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : GEO-POLITICAL ISSUES","question":"Which of the following best explains the influx of refuges from Liberia to Ghana?","images":[],"options":{"A":"Wages are higher in Ghana than in Liberia","B":"Loss of markets in Liberia for products","C":"Food shortage in Liberia caused by over population","D":"Great suffering in Liberia from ethnic tensions and civil war"},"answer":"D","explanation":"The refuges fled their country during the acute Civil war in Liberia 1989 to 1996 and as well as the second Brutal civil war between 1999 and 2003.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2010>49","subject":"Geography","year":"2010","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"One outstanding benefit of lumbering to an economy is that it","images":[],"options":{"A":"leads to depletion of forest","B":"earns foreign exchange","C":"leads to soil erosion","D":"causes flooding"},"answer":"B","explanation":"One outstanding benefit of lumbering to an economy is that it earns foreign exchange. Lumbering involves the cutting down of trees to supply raw materials for the wood and paper industry. These products can be exported to other countries, earning the country foreign exchange. While lumbering can lead to negative environmental impacts like depletion of forests, soil erosion, and flooding, these are not benefits to an economy.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2010>50","subject":"Geography","year":"2010","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Which of the following is not a member country of ECOWAS?","images":[],"options":{"A":"Nigeria","B":"Ghana","C":"Cameroon","D":"Liberia"},"answer":"C","explanation":"The member country of ECOWAS include:  * Benin * Cote d' lvoire * Gambia * Ghana * Guinea   * Guine-Bisau * Liberia * Mali * Niger * Nigeria   * Senegal * Sierra Leone * Togo * Burkina Faso * Cape Verde     N.B: Cameroon is in Central Africa","marks":"1","difficulty":"1"}];